import{_ as d,o as a,c as r,ai as e}from"./chunks/framework.SowO7O0D.js";const g=JSON.parse('{"title":"第三课：A股交易规则","description":"","frontmatter":{},"headers":[],"relativePath":"guide/03-trading-rules.md","filePath":"guide/03-trading-rules.md","lastUpdated":0}'),l={name:"guide/03-trading-rules.md"};function o(h,t,i,n,s,b){return a(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="第三课-a股交易规则" tabindex="-1">第三课：A股交易规则 <a class="header-anchor" href="#第三课-a股交易规则" aria-label="Permalink to “第三课：A股交易规则”">​</a></h1><p>开户完成后，正式炒股前必须了解的规则。这一课讲的是<strong>A股市场独特的交易制度</strong>，如果不理解这些规则，你可能会吃亏。</p><h2 id="一、交易时间" tabindex="-1">一、交易时间 <a class="header-anchor" href="#一、交易时间" aria-label="Permalink to “一、交易时间”">​</a></h2><p>A股的交易时间固定，不是24小时随时可买：</p><table tabindex="0"><thead><tr><th>交易时段</th><th>时间</th><th>说明</th></tr></thead><tbody><tr><td>早盘集合竞价</td><td>9:15 - 9:25</td><td>可挂单，9:25成交</td></tr><tr><td>连续竞价（上午）</td><td>9:30 - 11:30</td><td>正常交易</td></tr><tr><td>午间休市</td><td>11:30 - 13:00</td><td>不能交易</td></tr><tr><td>连续竞价（下午）</td><td>13:00 - 15:00</td><td>正常交易</td></tr><tr><td>尾盘集合竞价</td><td>14:57 - 15:00</td><td>沪深主板最后3分钟</td></tr></tbody></table><blockquote><p>💡 <strong>重要</strong>：周末和法定节假日A股休市。</p></blockquote><h3 id="集合竞价小知识" tabindex="-1">集合竞价小知识 <a class="header-anchor" href="#集合竞价小知识" aria-label="Permalink to “集合竞价小知识”">​</a></h3><ul><li><strong>9:15 - 9:20</strong>：可以挂单也可以撤单（庄家爱在这里&quot;演戏&quot;）</li><li><strong>9:20 - 9:25</strong>：可以挂单，<strong>不能撤单</strong></li><li><strong>9:25 - 9:30</strong>：系统接受报价，但不在这个时间段成交</li></ul><blockquote><p>🚨 新手注意：9:15-9:20的挂单可能是假的，庄家故意挂涨停价引诱你追高，9:20之前全部撤单。</p></blockquote><h2 id="二、t-1制度" tabindex="-1">二、T+1制度 <a class="header-anchor" href="#二、t-1制度" aria-label="Permalink to “二、T+1制度”">​</a></h2><p><strong>这是A股最重要的规则之一，必须记住！</strong></p><h3 id="什么是t-1" tabindex="-1">什么是T+1？ <a class="header-anchor" href="#什么是t-1" aria-label="Permalink to “什么是T+1？”">​</a></h3><blockquote><p><strong>T日 = 交易日当天</strong>。T+1 = 交易日+1天。</p></blockquote><p><strong>今天买的股票，今天不能卖，必须等到明天。</strong></p><h3 id="生活比喻" tabindex="-1">生活比喻 <a class="header-anchor" href="#生活比喻" aria-label="Permalink to “生活比喻”">​</a></h3><p>就像<strong>网购预售</strong>：</p><ul><li>今天下单（买股票）</li><li>今天不能退货（不能卖）</li><li>必须等明天发货了才能操作（第二天才能卖）</li></ul><h3 id="举例" tabindex="-1">举例 <a class="header-anchor" href="#举例" aria-label="Permalink to “举例”">​</a></h3><table tabindex="0"><thead><tr><th>时间</th><th>操作</th><th>结果</th></tr></thead><tbody><tr><td>周一买入</td><td>10元买了100股X股票</td><td>成交</td></tr><tr><td>周一卖出</td><td>想卖X股票</td><td>❌ 失败！系统拒绝</td></tr><tr><td>周二卖出</td><td>11元卖100股X股票</td><td>✅ 成功！赚了100元</td></tr></tbody></table><h3 id="t-1的原因" tabindex="-1">T+1的原因 <a class="header-anchor" href="#t-1的原因" aria-label="Permalink to “T+1的原因”">​</a></h3><p>表面看起来是限制，实际上是<strong>保护散户</strong>：</p><ul><li>防止过度投机</li><li>避免当天频繁买卖放大亏损</li></ul><h2 id="三、涨跌停板制度" tabindex="-1">三、涨跌停板制度 <a class="header-anchor" href="#三、涨跌停板制度" aria-label="Permalink to “三、涨跌停板制度”">​</a></h2><p>每个股票每天最大涨跌幅度有限制，不能无限涨或跌：</p><table tabindex="0"><thead><tr><th>股票类型</th><th>涨跌停幅度</th><th>说明</th></tr></thead><tbody><tr><td>主板（沪深）</td><td>±10%</td><td>大多数股票</td></tr><tr><td>ST股</td><td>±5%</td><td>连续亏损被特别处理的股票</td></tr><tr><td>创业板</td><td>±20%</td><td>科创板也±20%</td></tr><tr><td>科创板</td><td>±20%</td><td>创新型企业为主</td></tr></tbody></table><h3 id="举例-1" tabindex="-1">举例 <a class="header-anchor" href="#举例-1" aria-label="Permalink to “举例”">​</a></h3><p>某股票今天收盘10元，那么：</p><ul><li>涨停价 = 10 × 1.10 = <strong>11.00元</strong></li><li>跌停价 = 10 × 0.90 = <strong>9.00元</strong></li></ul><p>当天价格最多涨到11元，或跌到9元，就不会再动了。</p><h3 id="涨停板的特点" tabindex="-1">涨停板的特点 <a class="header-anchor" href="#涨停板的特点" aria-label="Permalink to “涨停板的特点”">​</a></h3><ol><li><strong>买不进去是常态</strong>：大家都想买，撮合成交按&quot;时间优先、价格优先&quot;</li><li><strong>涨停不代表明天还会涨</strong>：可能是主力拉高出货</li><li><strong>追涨停风险极大</strong>：俗称&quot;打板&quot;，专业投资者都不一定玩得转</li></ol><blockquote><p>🚨 <strong>新手警告</strong>：看到涨停就冲进去买，很可能第二天开盘就低开，被套在高处。</p></blockquote><h2 id="四、最小交易单位" tabindex="-1">四、最小交易单位 <a class="header-anchor" href="#四、最小交易单位" aria-label="Permalink to “四、最小交易单位”">​</a></h2><p>A股以<strong>手</strong>为单位，1手 = 100股。</p><p>所以你买股票，最少买100股，买入数量必须是100的整数倍。</p><h3 id="举例-2" tabindex="-1">举例 <a class="header-anchor" href="#举例-2" aria-label="Permalink to “举例”">​</a></h3><p>某股票股价 = 50元/股</p><ul><li>最少买1手 = 100股 = <strong>5000元</strong></li><li>再想买3手 = 300股 = <strong>15000元</strong></li></ul><blockquote><p>💡 所以买股票之前要先算好：股价 × 100 = 最低买入金额</p></blockquote><h2 id="五、股票代码基础知识" tabindex="-1">五、股票代码基础知识 <a class="header-anchor" href="#五、股票代码基础知识" aria-label="Permalink to “五、股票代码基础知识”">​</a></h2><table tabindex="0"><thead><tr><th>代码</th><th>市场</th><th>示例</th></tr></thead><tbody><tr><td>600xxx</td><td>上交所主板</td><td>600519（贵州茅台）</td></tr><tr><td>601xxx</td><td>上交所主板</td><td>601318（中国平安）</td></tr><tr><td>000xxx</td><td>深交所主板</td><td>000858（五粮液）</td></tr><tr><td>002xxx</td><td>深交所中小板</td><td>002594（比亚迪）</td></tr><tr><td>300xxx</td><td>深交所创业板</td><td>300750（宁德时代）</td></tr><tr><td>688xxx</td><td>上交所科创板</td><td>688981（中芯国际）</td></tr></tbody></table><blockquote><p>💡 一看到代码开头，大概就知道是什么板块的股票了。</p></blockquote><h2 id="六、当日涨跌怎么看" tabindex="-1">六、当日涨跌怎么看？ <a class="header-anchor" href="#六、当日涨跌怎么看" aria-label="Permalink to “六、当日涨跌怎么看？”">​</a></h2><table tabindex="0"><thead><tr><th>术语</th><th>含义</th></tr></thead><tbody><tr><td>涨幅</td><td>相比昨日收盘涨了百分之几</td></tr><tr><td>振幅</td><td>当日最高价到最低价的波动幅度</td></tr><tr><td>量比</td><td>今日成交量与过去5日平均的比值</td></tr><tr><td>换手率</td><td>当日成交股数占总流通股本的比例</td></tr></tbody></table><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to “思考题”">​</a></h2><blockquote><p>某股票代码是300xxx，它在哪个交易所上市？涨跌幅限制是多少？</p></blockquote><hr><p><strong>下一课预告</strong>：规则懂了，下一课学习<strong>什么是指数</strong>——上证指数、沪深300、创业板指，这些到底代表什么。</p>',48)])])}const p=d(l,[["render",o]]);export{g as __pageData,p as default};
